import React, { useCallback, useEffect, useRef, useState } from 'react';
import { SET_FEEDBACK, SET_ORIGINAL_IMAGE } from 'actions';
import { useStore } from 'hooks';

var BRUSH = 30;

var EraserOptions = function () {
  var { dispatch, originalImage } = useStore();
  var [busy, setBusy] = useState(false);
  var [dirty, setDirty] = useState(false);
  var cv = useRef(null);
  var ctx = useRef(null);
  var dw = useRef(false);

  var clearAll = useCallback(function () {
    var c = cv.current;
    if (!c) return;
    var ct = ctx.current;
    ct.clearRect(0, 0, c.width, c.height);
    setDirty(false);
  }, []);

  var snap = useCallback(function () {
    var c = cv.current;
    if (!c) return null;
    var stageCanvas = c.parentElement.querySelector('canvas');
    if (!stageCanvas) return null;
    return stageCanvas.toDataURL('image/png');
  }, []);

  var erase = useCallback(async function () {
    if (!dirty) return;
    setBusy(true);
    var src = snap();
    if (!src) { clearAll(); setBusy(false); return; }

    var maskC = document.createElement('canvas');
    var mw = originalImage?.width || 512;
    var mh = originalImage?.height || 512;
    maskC.width = mw; maskC.height = mh;
    var mctx = maskC.getContext('2d');
    mctx.fillStyle = 'black'; mctx.fillRect(0, 0, mw, mh);
    try {
      var data = ctx.current.getImageData(0, 0, cv.current.width, cv.current.height);
      for (var y = 0; y < cv.current.height; y++) {
        for (var x = 0; x < cv.current.width; x++) {
          if (data.data[(y * cv.current.width + x) * 4 + 3] > 0) {
            var dx = Math.round(x * mw / cv.current.width);
            var dy = Math.round(y * mh / cv.current.height);
            mctx.fillStyle = 'white';
            mctx.fillRect(dx - 5, dy - 5, 11, 11);
          }
        }
      }
    } catch (me) {}

    try {
      var r = await fetch('/api/v1/inpaint', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ image: src.split(',')[1], mask: maskC.toDataURL('image/png').split(',')[1] }),
      });
      if (!r.ok) throw new Error('服务器返回错误');
      var b = await r.blob();
      var u = URL.createObjectURL(b);
      var img = new Image();
      img.onload = function () {
        dispatch({ type: SET_ORIGINAL_IMAGE, payload: { originalImage: img } });
        clearAll(); setBusy(false); URL.revokeObjectURL(u);
      };
      img.onerror = function () { clearAll(); setBusy(false); };
      img.src = u;
    } catch (e) {
      clearAll(); setBusy(false);
      dispatch({
        type: SET_FEEDBACK,
        payload: { feedback: { message: '消除失败: ' + e.message, status: 'warning' } },
      });
    }
  }, [dirty, snap, originalImage, dispatch, clearAll]);

  useEffect(function () {
    var id = setInterval(function () {
      var container = document.querySelector('.FIE_canvas-node');
      if (!container) return;
      var content = container.querySelector('.konvajs-content');
      if (!content) return;
      var stageCanvas = content.querySelector('canvas');
      if (!stageCanvas || stageCanvas.width === 0) return;

      clearInterval(id);

      var c = document.createElement('canvas');
      c.width = stageCanvas.width;
      c.height = stageCanvas.height;
      c.style.cssText = 'position:absolute;inset:0;z-index:10;cursor:cross;';
      content.appendChild(c);
      cv.current = c;
      var ct = c.getContext('2d');
      ctx.current = ct;
      ct.strokeStyle = 'red'; ct.lineWidth = BRUSH;
      ct.lineCap = 'round'; ct.lineJoin = 'round';

      var down = function (e) {
        dw.current = true;
        var r = c.getBoundingClientRect();
        ct.beginPath();
        ct.moveTo(e.clientX - r.left, e.clientY - r.top);
      };
      var move = function (e) {
        if (!dw.current) return;
        var r = c.getBoundingClientRect();
        ct.lineTo(e.clientX - r.left, e.clientY - r.top);
        ct.stroke();
      };
      var up = function () {
        dw.current = false;
        setDirty(true);
      };

      c.addEventListener('mousedown', down);
      c.addEventListener('mousemove', move);
      c.addEventListener('mouseup', up);
    }, 200);

    return function () { clearInterval(id); };
  }, []);

  var bs = { padding: '4px 16px', borderRadius: 4, border: 'none', background: '#E53D3D', color: '#fff', cursor: 'pointer', fontSize: 13 };
  var cs = { padding: '4px 12px', borderRadius: 4, border: '1px solid #ccc', background: 'transparent', cursor: 'pointer', fontSize: 13 };

  return React.createElement('div', { style: { display: 'flex', gap: 8, alignItems: 'center', padding: '0 8px' } },
    React.createElement('span', { style: { fontSize: 12, color: '#999' } },
      busy ? '消除处理中...' : (dirty ? '已涂抹，点击消除' : '在图片上涂抹要消除的区域')
    ),
    dirty && !busy && React.createElement('button', { key: 'e', onClick: erase, style: bs }, '消除'),
    dirty && !busy && React.createElement('button', { key: 'c', onClick: clearAll, style: cs }, '取消')
  );
};

export default EraserOptions;
