export const CANCEL_CROP = 'CANCEL_CROP';

const cancelCrop = (state) => {
  const oldCrop = state.adjustments?.crop ?? {};
  return {
    ...state,
    cropApplied: false,
    adjustments: {
      ...state.adjustments,
      crop: {
        ...oldCrop,
        width: null,
        height: null,
        x: 0,
        y: 0,
      },
    },
  };
};

export default cancelCrop;
