import React from 'react';
import { APPLY_CROP, CANCEL_CROP } from 'actions';
import { useStore } from 'hooks';
import { TOOLS_IDS } from 'utils/constants';
import {
  StyledCropOptions,
  StyledCropActionButton,
} from './Crop.styled';

const CropOptions = () => {
  const { dispatch, t, adjustments: { crop } = {}, cropApplied } = useStore();
  const hasCrop = crop?.width != null && crop?.height != null;

  if (!hasCrop || cropApplied) {
    return null;
  }

  return (
    <StyledCropOptions>
      <StyledCropActionButton
        size="sm"
        color="primary"
        onClick={() => dispatch({ type: APPLY_CROP })}
      >
        {t('apply')}
      </StyledCropActionButton>
      <StyledCropActionButton
        size="sm"
        color="basic"
        onClick={() => dispatch({ type: CANCEL_CROP })}
      >
        {t('cancel') || 'Cancel'}
      </StyledCropActionButton>
    </StyledCropOptions>
  );
};

export default CropOptions;
